#!/usr/bin/perl -w
use CGI;
use CGI::Carp qw(fatalsToBrowser);
use strict;
use warnings;

my $q = new CGI;

my $next = $q->param('next');

if (defined($next)) {
    print "Location: $next\n\n";
} else {
    print "Location: /\n\n";
}

exit 0;